import boto3

def create_sns_subscription(topic_arn):
    # Create an SNS client using boto3
    sns_client = boto3.client('sns')
    
    # Get user input for the subscription endpoint
    user_provided_url = input("Enter the subscription endpoint URL: ")
    
    try:
        # Subscribe to the SNS topic without validation
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_provided_url
        )
        
        print(f"Subscription successful with ARN: {response['SubscriptionArn']}")
    except Exception as e:
        print(f"Failed to subscribe: {e}")

# Example usage
